#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007ULL

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        uint64_t N;
        scanf("%llu", &N);
        int k;
        scanf("%d", &k);
        int L[k];
        for (int i = 0; i < k; i++) {
            scanf("%d", &L[i]);
        }
        uint64_t dp[N + 1] = {0};
        dp[0] = 1;
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j < k; j++) {
                if (i >= L[j]) {
                    dp[i] = (dp[i] + dp[i - L[j]]) % MOD;
                }
            }
        }
        printf("%llu\n", dp[N]);
    }
    return 0;
}

